from ag2.groupchat import GroupChat, GroupChatManager
from ag2.core.callbacks import on_message

class SafeGroupChatManager(GroupChatManager):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.max_rounds = 10
        self.round_count = 0
        self.initial_topic = None

    async def select_speaker(self, last_speaker, selector):
        self.round_count += 1
        if self.round_count > self.max_rounds:
            return None  # Terminate
        return await super().select_speaker(last_speaker, selector)

from ag2.agents import AssistantAgent

class FactCheckAgent(AssistantAgent):
    async def a_generate_reply(self, messages, sender, config):
        response = await super().a_generate_reply(messages, sender, config)
        if self._contains_facts(response):
            # Trigger human review
            approval = await self._request_human_review(response)
            if not approval:
                return "[HUMAN_REVIEW_REJECTED] Please verify facts before proceeding."
        return response

    def _contains_facts(self, text: str) -> bool:
        import re
        return bool(re.search(r'\b\d{4}\b|\bTrue\b|\bFalse\b', text))

from ag2.groupchat import RoundRobinSpeakerSelectionMethod

class FairSpeakerSelection(RoundRobinSpeakerSelectionMethod):
    def __init__(self, agents, max_dominant_turns=3):
        super().__init__(agents)
        self.speaker_turns = {agent: 0 for agent in agents}
        self.max_dominant_turns = max_dominant_turns

    def select_speaker(self, last_speaker, states):
        least_spoken = min(self.speaker_turns, key=self.speaker_turns.get)
        if self.speaker_turns[least_spoken] < self.max_dominant_turns:
            return least_spoken
        return super().select_speaker(last_speaker, states)
